(function(){
  const AUDIO_UNAVAILABLE = "اس آلے پر اردو آواز دستیاب نہیں ہے۔";
  let audioPlaying = false;

  function data(){
    return window.ACS_LESSON_DATA || {};
  }

  window.openModal = function(id){
    const el = document.getElementById(id);
    if(el) el.classList.add('open');
  };

  window.closeModal = function(id){
    const el = document.getElementById(id);
    if(el) el.classList.remove('open');
  };

  window.goLesson = function(){
    const input = document.getElementById('jumpInput');
    const n = input ? parseInt(input.value, 10) : 0;
    if(!n || n < 1 || n > 150) return;
    window.location.href = 'L' + String(n).padStart(3, '0') + '.html';
  };

  function getBestVoice(){
    const d = data();
    const pageLang = d.pageLang || "ur";
    const audioLang = d.audioLang || "ur-PK";
    const voices = window.speechSynthesis ? speechSynthesis.getVoices() : [];
    return voices.find(v => (v.lang || '').toLowerCase().startsWith(audioLang.toLowerCase())) ||
           voices.find(v => (v.lang || '').toLowerCase().startsWith(pageLang.toLowerCase())) ||
           false;
  }

  window.toggleAudio = function(){
    const btn = document.getElementById('audioBtn');
    const nav = document.getElementById('bottomNav');
    const d = data();
    if(!window.speechSynthesis){
      alert(AUDIO_UNAVAILABLE);
      return;
    }
    if(audioPlaying){
      speechSynthesis.cancel();
      audioPlaying = false;
      if(btn) btn.textContent = "سنیں 🔊";
      if(nav) nav.style.display = 'grid';
      return;
    }
    const utter = new SpeechSynthesisUtterance(d.lessonText || document.body.innerText);
    const voice = getBestVoice();
    utter.lang = d.audioLang || "ur-PK";
    if(voice) utter.voice = voice;
    utter.rate = 0.88;
    utter.pitch = 1;
    utter.onend = function(){
      audioPlaying = false;
      if(btn) btn.textContent = "سنیں 🔊";
      if(nav) nav.style.display = 'grid';
    };
    utter.onerror = function(){
      audioPlaying = false;
      if(btn) btn.textContent = "سنیں 🔊";
      if(nav) nav.style.display = 'grid';
      alert(AUDIO_UNAVAILABLE);
    };
    audioPlaying = true;
    if(btn) btn.textContent = "روکیں ■";
    if(nav) nav.style.display = 'none';
    speechSynthesis.cancel();
    speechSynthesis.speak(utter);
  };

  if(window.speechSynthesis){
    speechSynthesis.onvoiceschanged = function(){ speechSynthesis.getVoices(); };
  }

  window.aiHelp = function(mode){
    const d = data();
    const prompt = (d.aiPrompts && d.aiPrompts[mode]) || (d.aiPrompts && d.aiPrompts.explain) || "اس سبق کو آسان اردو میں سمجھائیں۔";
    const out = document.getElementById('aiOutput');
    if(out) out.textContent = prompt + "\n\n" + (d.lessonText || "").slice(0, 900);
  };

  window.shareWhatsApp = function(){
    window.open("https://wa.me/?text=" + encodeURIComponent(document.title + " " + window.location.href), "_blank");
  };

  window.copyShareLink = function(url){
    if(navigator.clipboard && navigator.clipboard.writeText){
      navigator.clipboard.writeText(url).then(function(){ alert("لنک کاپی ہو گیا"); });
    } else {
      const t = document.createElement("textarea");
      t.value = url;
      document.body.appendChild(t);
      t.select();
      document.execCommand("copy");
      document.body.removeChild(t);
      alert("لنک کاپی ہو گیا");
    }
  };
})();